using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow tests
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10,  0.00,  DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10,  0.00,  DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0, 199.98,  DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1,  0.10, DisplayName = "Negative unit price throws")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    [DataRow(10.00, 1,  -0.1, DisplayName = "Negative tax rate throws")]
    [DataRow(10.00, 1,  1.01, DisplayName = "Tax rate > 1 throws")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData tests
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> ValidDiscountCases =>
    [
        [100.00m,  0m,   100.00m, "No discount"],
        [100.00m,  10m,   90.00m, "10% off"],
        [100.00m,  50m,   50.00m, "Half price"],
        [100.00m, 100m,    0.00m, "Full discount"],
        [59.99m,   15m,  50.9915m, "Fractional result"],
        [0.00m,    25m,    0.00m, "Zero price, any discount"],
    ];

    [TestMethod]
    [DynamicData(nameof(ValidDiscountCases))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    public static IEnumerable<object[]> InvalidDiscountCases =>
    [
        [100.00m, -1m,    "Negative discount"],
        [100.00m, 100.01m, "Discount > 100%"],
    ];

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases))]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent, string scenario)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent),
            $"Expected exception for scenario: {scenario}");
    }

    // ───────────────────────────────────────────────
    //  FormatPrice – DataRow tests
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(9.99,  "$",  "$9.99",  DisplayName = "Default currency symbol")]
    [DataRow(9.99,  "€",  "€9.99",  DisplayName = "Euro symbol")]
    [DataRow(1000.5, "$", "$1000.50", DisplayName = "Pads to two decimals")]
    [DataRow(0.0,   "¥",  "¥0.00",  DisplayName = "Zero with yen symbol")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

